export interface Spell {
  id: string;
  name: string;
  description: string;
  
  // 5e Spell Structure (System Ascendant Themed)
  level: number;                    // 0-9 spell level
  school: string;                   // School of magic (Shadow, Void, Abyssal, etc.)
  castingTime: string;              // "1 action", "1 bonus action", "instant"
  range: string | {                // "Self", "Touch", "60 ft", etc.
    type: string;
    value?: number;
    unit?: string;
  };
  components: {
    verbal: boolean;
    somatic: boolean;
    material: boolean | string;    // false or essence requirement
  };
  duration: string | {             // "Instantaneous", "1 minute", etc.
    type: string;
    time?: string;
  };
  concentration: boolean;
  ritual: boolean;
  
  // System Ascendant metadata
  type: 'Attack' | 'Defense' | 'Utility' | 'Healing';
  rank: 'D' | 'C' | 'B' | 'A' | 'S';  // Gate Rank equivalent
  image: string;
  effect: string;
  
  // System Ascendant 5e mechanics
  atHigherLevels: string;           // Higher level casting effects
  classes: string[];                // Which Hunter classes can cast
  
  // Additional mechanics (System Ascendant themed)
  savingThrow?: {
    ability: string;
    dc: string | number;
    success: string;
    failure: string;
  };
  spellAttack?: {
    type: 'melee' | 'ranged';
    ability: string;
    damage: string;
  };
  area?: {
    type: string;
    size: string;
    shape: 'sphere' | 'cube' | 'cone' | 'line' | 'cylinder';
  };
  
  // System Ascendant specific fields
  essenceRequirement?: string;      // Essence cost instead of material components
  hunterClass?: string[];           // Specific Hunter class requirements
  systemAwakening?: boolean;        // Requires System Awakening to use
}

